from typing import (
    Any,
    BinaryIO,
    Callable,
    Dict,
    Iterable,
    Optional,
    Type,
    TypeVar,
    cast,
)

from fastapi._compat import (
    PYDANTIC_V2,
    CoreSchema,
    GetJsonSchemaHandler,
    JsonSchemaValue,
    with_info_plain_validator_function,
)
from starlette.datastructures import URL as URL  # noqa: F401
from starlette.datastructures import Address as Address  # noqa: F401
from starlette.datastructures import FormData as FormData  # noqa: F401
from starlette.datastructures import Headers as Headers  # noqa: F401
from starlette.datastructures import QueryParams as QueryParams  # noqa: F401
from starlette.datastructures import State as State  # noqa: F401
from starlette.datastructures import UploadFile as StarletteUploadFile
from typing_extensions import Annotated, Doc  # type: ignore [attr-defined]


class UploadFile(StarletteUploadFile):
    """
    A file uploaded in a request.

    Define it as a *path operation function* (or dependency) parameter.

    If you are using a regular `def` function, you can use the `upload_file.file`
    attribute to access the raw standard Python file (blocking, not async), useful and
    needed for non-async code.

    Read more about it in the
    [FastAPI docs for Request Files](https://fastapi.tiangolo.com/tutorial/request-files/).

    ## Example

    '''python
    from typing import Annotated

    from fastapi import FastAPI, File, UploadFile

    app = FastAPI()


    @app.post("/files/")
    async def create_file(file: Annotated[bytes, File()]):
        return {"file_size": len(file)}


    @app.post("/uploadfile/")
    async def create_upload_file(file: UploadFile):
        return {"filename": file.filename}
    '''
    """

    file: Annotated[
        BinaryIO,
        Doc("The standard Python file object (non-async)."),
    ]
    filename: Annotated[Optional[str], Doc("The original file name.")]
    size: Annotated[Optional[int], Doc("The size of the file in bytes.")]
    headers: Annotated[Headers, Doc("The headers of the request.")]
    content_type: Annotated[
        Optional[str], Doc("The content type of the request, from the headers.")
    ]

    async def write(
        self,
        data: Annotated[
            bytes,
            Doc(
                """
                The bytes to write to the file.
                """
            ),
        ],
    ) -> None:
        """
        Write some bytes to the file.

        You normally wouldn't use this from a file you read in a request.

        To be awaitable, compatible with async, this is run in threadpool.
        """
        return await super().write(data)

    async def read(
        self,
        size: Annotated[
            int,
            Doc(
                """
                The number of bytes to read from the file.
                """
            ),
        ] = -1,
    ) -> bytes:
        """
        Read some bytes from the file.

        To be awaitable, compatible with async, this is run in threadpool.
        """
        return await super().read(size)

    async def seek(
        self,
        offset: Annotated[
            int,
            Doc(
                """
                The position in bytes to seek to in the file.
                """
            ),
        ],
    ) -> None:
        """
        Move to a position in the file.

        Any next read or write will be done from that position.

        To be awaitable, compatible with async, this is run in threadpool.
        """
        return await super().seek(offset)

    async def close(self) -> None:
        """
        Close the file.

        To be awaitable, compatible with async, this is run in threadpool.
        """
        return await super().close()

    @classmethod
    def __get_validators__(cls: Type["UploadFile"]) -> Iterable[Callable[..., Any]]:
        """Yield validators compatible with pydantic v1."""
        yield cls.validate

    @classmethod
    def validate(cls: Type["UploadFile"], v: Any) -> Any:
        """Validate that the value is a Starlette UploadFile instance for pydantic v1."""
        if not isinstance(v, StarletteUploadFile):
            raise TypeError("UploadFile required")
        return v

    @classmethod
    def _validate(cls: Type["UploadFile"], v: Any, info: Any = None) -> Any:
        """Internal validator used for pydantic v2 integration."""
        if not isinstance(v, StarletteUploadFile):
            raise TypeError("UploadFile required")
        return v

    @classmethod
    def __get_pydantic_json_schema__(
        cls, _handler: GetJsonSchemaHandler
    ) -> JsonSchemaValue:
        """Provide JSON Schema representation for pydantic."""
        # Represent upload files as binary strings in JSON Schema
        return {"title": cls.__name__, "type": "string", "format": "binary"}

    @classmethod
    def __modify_schema__(cls, field_schema: Dict[str, Any]) -> None:
        """Modify pydantic v1 schema to represent upload files as binary strings."""
        field_schema.update({"type": "string", "format": "binary", "title": cls.__name__})

    @classmethod
    def __get_pydantic_core_schema__(
        cls, _source: Type[Any], handler: Any
    ) -> "CoreSchema":
        """Provide pydantic v2 core schema using a plain validator function."""
        # Use helper to wrap our validator so pydantic v2 can call it with info
        return with_info_plain_validator_function(cls._validate)

    def __init__(self, *args: Any, **kwargs: Any) -> None:
        """Initialize the UploadFile instance by delegating to Starlette's UploadFile."""
        super().__init__(*args, **kwargs)

    def __bool__(self) -> bool:
        """Return True if the upload file has either a file object or a filename."""
        return bool(getattr(self, "file", None) or getattr(self, "filename", None))

    def __eq__(self, other: Any) -> bool:
        """Compare UploadFile instances by file object identity and metadata."""
        if not isinstance(other, StarletteUploadFile):
            return NotImplemented
        # Prefer identity of the file object; fall back to filename/content_type comparison
        same_file = getattr(self, "file", None) is getattr(other, "file", None)
        same_name = getattr(self, "filename", None) == getattr(other, "filename", None)
        same_content_type = getattr(self, "content_type", None) == getattr(
            other, "content_type", None
        )
        return same_file and same_name and same_content_type